use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

struct DataView<'a> { raw_bytes: &'a [u8] }

impl<'a> DataView<'a> {
    fn new(raw_bytes: &'a [u8]) -> Self {
        DataView { raw_bytes }
    }

    fn get_slice(&self, start: usize, len: usize) -> Option<&'a [u8]> {
        if start + len > self.raw_bytes.len() {
            None
        } else {
            Some(&self.raw_bytes[start..start + len])
        }
    }
}

