use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct UserActionRecord {
    timestamp: String,
    user_id: u32,
    action: String,
}

fn parse_log_line(line: &str) -> Option<UserActionRecord> {
    let parts: Vec<&str> = line.split("|").collect();
    if parts.len() < 3 {
        return None;
    }

    let timestamp = parts[0].trim().to_string();
    let user_id_str = parts[1].trim();
    let action = parts[2].trim().to_string();

    match user_id_str.parse::<u32>() {
        Ok(user_id) => Some(UserActionRecord {
            timestamp,
            user_id,
            action,
        }),
        Err(_) => None,
    }
}

fn process_log_file(file_path: &str, target_action: &str) -> io::Result<Vec<String>> {
    let file = File::open(file_path)?;
    let reader = BufReader::new(file);

    let mut matching_actions = Vec::new();

    for line_result in reader.lines() {
        match line_result {
            Ok(line) => {
                if let Some(record) = parse_log_line(&line) {
                    if record.action.contains(target_action) {
                        matching_actions.push(format!("{}: User {} performed action \"{}\"", record.timestamp, record.user_id, record.action));
                    }
                }
            },
            Err(e) => return Err(io::Error::new(io::ErrorKind::Other, format!("Failed to read line: {}", e))),
        }
    }
    Ok(matching_actions)
}

fn main() -> io::Result<()> {
    let dummy_log_path = "cms_access.log";
