use std::fs::OpenOptions;
use std::io::{self, BufReader, Read, BufRead};
use std::path::Path;

struct JsonChunk {
    start: usize,
    end: usize,
}

fn find_next_json_chunk(reader: &mut impl BufRead) -> io::Result<Option<JsonChunk>> {
    let mut buffer = Vec::new();
    let mut current_offset = 0;

    if reader.read_to_end(&mut buffer)? == 0 {
        return Ok(None);
    }

    let data = &buffer[current_offset..];

    let start_char = b'{';
    let end_char = b'}';

    for i in 0..data.len() {
        if data[i] == start_char && (i + 1 < data.len()) {
            let mut balance = 1;
            for j in i + 1..data.len() {
                match data[j] {
                    b'{' => balance += 1,
                    b'}' => {
                        balance -= 1;
                        if balance == 0 {
                            return Ok(Some(JsonChunk { start: i, end: j + 1 }));
                        }
                    },
                    _ => {}
                }
            }
        }
    }

    Ok(None)
}

fn main() -> io::Result<()> {
    let path = Path::new("test.log");

    if !path.exists() {
        write_dummy_file(path)?;
    }

    let file = OpenOptions::new().read(true).open(path)?;
    let mut reader = BufReader::new(file);

    match find_next_json_chunk(&mut reader)? {
        Some(chunk) => {
            println!("Found potential JSON chunk spanning bytes: {}", chunk.start);
        }
        None => {
            println!("No complete JSON structure found in the current read buffer.");
        }
    }

    Ok(())
}

fn write_dummy_file(path: &Path) -> io::Result<()> {
