use std::io::{self, Cursor, Read};
use std::mem;

struct GameStateRecord {
    timestamp: u64,
    player_id: u32,
    action_type: u16,
    payload_size: u32,

}

fn parse_record(cursor: &mut Cursor<&[u8]>) -> io::Result<GameStateRecord> {
    let mut buffer = [0; 8 + 4 + 2 + 4];
    cursor.read(&mut buffer)?;

    let timestamp = u64::from_le_bytes(buffer[0..8].try_into().unwrap());
    let player_id = u32::from_le_bytes(buffer[8..12].try_into().unwrap());
    let action_type = u16::from_le_bytes(buffer[12..14].try_into().unwrap());
    let payload_size = u32::from_le_bytes(buffer[14..18].try_into().unwrap());

    Ok(GameStateRecord {
        timestamp,
        player_id,
        action_type,
        payload_size,
    })
}

fn process_game_state(data: &[u8]) -> io::Result<Vec<GameStateRecord>> {
    let mut cursor = Cursor::new(data);
    let mut records = Vec::new();
    const RECORD_HEADER_SIZE: usize = 18;

    while (cursor.position() as usize) + RECORD_HEADER_SIZE <= data.len() {
        match parse_record(&mut cursor) {
            Ok(record) => {
                records.push(record);
            }
            Err(e) if e.kind() == io::ErrorKind::UnexpectedEof => break,
            Err(e) => return Err(e),
        }
    }
    Ok(records)
}

fn main() -> io::Result<()> {
    let raw_data: Vec<u8> = vec![
        0xde, 0xad, 0xbe, 0xef, 0x00, 0x00, 0x00, 0x01,
        0xaa, 0xbb, 0xcc, 0xdd,
        0x01, 0x02,
        0x05, 0x00, 0x00, 0x00,
    ];

    let records = process_game_state(&raw_data)?;

    for record in records {
        println!("Found Record: Time={}, Player={}", record.timestamp, record.player_id);
    }

    Ok(())
}
